def predict(triples: list[Triple]) -> str:
    """
    Convert a list of Triple objects about an artist into a single fluent,
    context‑aware sentence. Information belonging to the same subject is merged
    into one clause using commas and appropriate conjunctions, producing a
    more natural complex sentence.
    """
    if not triples:
        return ""

    # Group triples by subject
    subject_map: dict[str, list[tuple[str, str]]] = {}
    for t in triples:
        subject_map.setdefault(t.subject, []).append((t.predicate, t.object))

    clauses: list[str] = []

    for subject, facts in subject_map.items():
        # Build descriptive pieces for this subject
        pieces: list[str] = []
        for p, o in facts:
            if p == "birthDate":
                pieces.append(f"was born on {o}")
            elif p == "birthYear":
                pieces.append(f"was born in {o}")
            elif p == "deathDate":
                pieces.append(f"died on {o}")
            elif p == "deathPlace":
                pieces.append(f"died in {o}")
            elif p == "origin":
                pieces.append(f"is from {o}")
            elif p == "nationality":
                pieces.append(f"is {o}")
            elif p == "genre":
                pieces.append(f"plays {o}")
            elif p == "instrument":
                pieces.append(f"plays the {o}")
            elif p == "occupation":
                pieces.append(f"works as {o}")
            elif p == "recordLabel":
                pieces.append(f"is signed to {o}")
            elif p == "associatedBand/associatedMusicalArtist":
                pieces.append(f"is associated with {o}")
            elif p == "background":
                pieces.append(f"has a background as {o}")
            elif p == "activeYearsStartYear":
                pieces.append(f"started their career in {o}")
            elif p == "activeYearsEndYear":
                pieces.append(f"ended their active years in {o}")
            elif p == "language":
                pieces.append(f"speaks {o}")
            elif p == "officialLanguage":
                pieces.append(f"has official language {o}")
            elif p == "capital":
                pieces.append(f"has capital {o}")
            elif p == "country":
                pieces.append(f"is located in {o}")
            elif p == "ethnicGroup":
                pieces.append(f"has ethnic group {o}")
            elif p == "currency":
                pieces.append(f"uses the {o}")
            elif p == "demonym":
                pieces.append(f"its people are called {o}")
            elif p == "populationDensity":
                pieces.append(f"has a population density of {o}")
            elif p == "areaTotal":
                pieces.append(f"covers an area of {o}")
            elif p == "elevationAboveTheSeaLevel":
                pieces.append(f"is at an elevation of {o} metres")
            else:
                # Generic fallback
                pieces.append(f"{p} {o}")

        # Combine pieces with commas, last piece preceded by 'and' if multiple
        if len(pieces) == 1:
            clause = f"{subject} {pieces[0]}"
        else:
            clause = f"{subject} " + ", ".join(pieces[:-1]) + f", and {pieces[-1]}"
        clauses.append(clause)

    # Join all subject clauses with semicolons
    sentence = "; ".join(clauses) + "."
    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END

